import requests
from urllib.parse import urlparse

ALLOWLIST = ['https://example.com', 'https://api.partner.com']

def is_valid_url(url):
    parsed_url = urlparse(url)
    if parsed_url.scheme not in ['http', 'https']:
        return False
    if parsed_url.hostname in ['localhost', '127.0.0.1'] or \
       parsed_url.hostname.startswith('192.168.') or \
       parsed_url.hostname.startswith('10.'):
        return False
    return any(parsed_url.hostname == urlparse(allowed).hostname for allowed in ALLOWLIST)

def fetch_url_content(url):
    if not is_valid_url(url):
        raise ValueError("Invalid URL or URL not allowed.")
    
    response = requests.get(url)
    response.raise_for_status()
    return response.text

